  <svg viewBox="0 0 700 300" xmlns="http://www.w3.org/2000/svg" style="width:100%;height:auto;background:#111113;border-radius:12px;border:1px solid rgba(255,255,255,.08);margin:20px 0">
    <text x="20" y="30" fill="#fafafa" font-size="16" font-weight="700" font-family="sans-serif">MNRS Rebrand Timeline — From Miners to AI Compute</text>
    <g font-family="sans-serif">
      <rect x="12" y="58" width="160" height="96" rx="10" fill="#1c1c1f" stroke="#3f3f46" stroke-width="1.6"/>
      <text x="92" y="88" fill="#e4e4e7" font-size="13" font-weight="700" text-anchor="middle">Jul 15 Filed</text>
      <text x="92" y="110" fill="#a1a1aa" font-size="12" text-anchor="middle">Form 485APOS</text>
      <text x="92" y="130" fill="#a1a1aa" font-size="12" text-anchor="middle">Filed with SEC</text>
